#!/bin/bash\n# Copyright (c) 2026 SPHARX. All Rights Reserved.\n# "From data intelligence emerges."\n#\n# OpenLab Quick Run Script\n# ========================\n# This script runs the Architect Agent demonstration.\n#\n# Usage:\n#   ./run.sh              # Run default demo\n#   ./run.sh architect    # Run architect agent\n#   ./run.sh test         # Run tests\n\nset -e\n\nSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"\ncd "$SCRIPT_DIR"\n\n# Colors for output\nRED='\033[0;31m'\nGREEN='\033[0;32m'\nYELLOW='\033[1;33m'\nNC='\033[0m' # No Color\n\necho -e "${GREEN}======================================${NC}"\necho -e "${GREEN}  OpenLab Agent Operating System${NC}"\necho -e "${GREEN}======================================${NC}"\necho ""\n\n# Check Python version\nPYTHON_VERSION=$(python3 --version 2>&1 || python --version 2>&1 | cut -d' ' -f2 | cut -d'.' -f1,2)\nif [ -z "$PYTHON_VERSION" ]; then\n    echo -e "${RED}Error: Python not found${NC}"\n    exit 1\nfi\n\necho -e "${YELLOW}Python version: $PYTHON_VERSION${NC}"\n\n# Check if virtual environment exists\nif [ ! -d "venv" ]; then\n    echo ""\n    echo -e "${YELLOW}Creating virtual environment...${NC}"\n    python3 -m venv venv\n    echo -e "${GREEN}Virtual environment created${NC}"\nfi\n\n# Activate virtual environment\necho ""\necho -e "${YELLOW}Activating virtual environment...${NC}"\nsource venv/bin/activate\n\n# Install dependencies\necho ""\necho -e "${YELLOW}Installing dependencies...${NC}"\npip install --upgrade pip\npip install -r openlab/requirements.txt\necho -e "${GREEN}Dependencies installed${NC}"\n\n# Run the demo\necho ""\necho -e "${GREEN}======================================${NC}"\necho -e "${GREEN}Running Architect Agent Demo${NC}"\necho -e "${GREEN}======================================${NC}"\necho ""\n\npython -m openlab.agents.architect.agent\n\necho ""\necho -e "${GREEN}======================================${NC}"\necho -e "${GREEN}Demo Complete${NC}"\necho -e "${GREEN}======================================${NC}"\n